import type * as React from 'react';

// architecture-badges.tsx
import {Tag, tagVariants} from '@/components/tag';
import {Tooltip, TooltipContent, TooltipTrigger} from '@/components/ui/tooltip';
import {cn} from '@/lib/utils';

type ArchitectureBadgesProps = React.ComponentProps<'div'> & {
  architectures: string[];
  /** Maximum chips to show before the overflow count. @default 2 */
  maxVisible?: number;
};

function formatArch(arch: string): string {
  return arch.replace('linux/', '').replace(/^arm\/.*/, 'arm');
}

/**
 * Compact chip list of architecture/platform strings.
 * Shows up to `maxVisible` chips; remaining count shown as "+N" with tooltip.
 *
 * **Requires a `TooltipProvider` ancestor** for the overflow tooltip to work.
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 2.1.1 Keyboard — overflow `+N` chip renders as a focusable `<button>`
 *   so the hidden architectures are reachable without a pointing device.
 * @wcag 1.4.13 Content on Hover or Focus — the tooltip appears on both hover
 *   and keyboard focus; its contents are also mirrored into the trigger's
 *   `aria-label` so screen-reader users do not depend on tooltip visibility.
 * @wcag 1.3.1 Info and Relationships — the overflow trigger has an accessible
 *   name that describes what `+N` represents and enumerates the hidden items.
 */
function ArchitectureBadges({
  architectures,
  maxVisible = 2,
  className,
  ...props
}: ArchitectureBadgesProps) {
  if (architectures.length === 0) return null;

  const visible = architectures.slice(0, maxVisible);
  const overflow = architectures.slice(maxVisible);
  const overflowLabel = overflow.map(formatArch).join(', ');

  return (
    <div
      data-slot="architecture-badges"
      className={cn('inline-flex flex-wrap items-center gap-1', className)}
      {...props}
    >
      {visible.map(arch => (
        <Tag key={arch} size="sm">
          {formatArch(arch)}
        </Tag>
      ))}
      {overflow.length > 0 && (
        <Tooltip>
          <TooltipTrigger asChild>
            <button
              type="button"
              data-slot="architecture-badges-overflow"
              aria-label={`${overflow.length} more ${overflow.length === 1 ? 'architecture' : 'architectures'}: ${overflowLabel}`}
              className={cn(
                tagVariants({size: 'sm'}),
                'cursor-default outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring'
              )}
            >
              +{overflow.length}
            </button>
          </TooltipTrigger>
          <TooltipContent>{overflowLabel}</TooltipContent>
        </Tooltip>
      )}
    </div>
  );
}

export {ArchitectureBadges};
export type {ArchitectureBadgesProps};
